31	/*!
32	  \file
33	  \brief The universal GEMM accommodates serial reductions, parallel reductions, batched strided, and
34	    batched array variants.
35	*/
36	
37	#pragma once
38	
39	// common
40	#include "cutlass/cutlass.h"
41	#include "cutlass/device_kernel.h"
