54	#include "cutlass/gemm/device/gemm_universal_base.h"
55	#include "cutlass/gemm/kernel/gemm_transpose_operands.h"
56	#include "cutlass/gemm/threadblock/threadblock_swizzle.h"
57	#include "cutlass/epilogue/threadblock/epilogue_with_visitor_callbacks.h"
58	
59	// 3.x
60	#include "cutlass/gemm/kernel/gemm_universal.hpp"
61	
62	////////////////////////////////////////////////////////////////////////////////
63	
64	namespace cutlass::gemm::device {
65	
66	////////////////////////////////////////////////////////////////////////////////
67	
68	/*!
69	  GemmUniversalAdapter is a stateful, reusable GEMM handle built around a kernel
70	  of type cutlass::gemm::kernel::Gemm or cutlass::gemm::kernel::GemmUniversal.
71	
72	  It manages the lifetime of the underlying `kernel::Params` struct, and exposes APIs
73	  to create it from the host facing arguments. For power users, new static methods
74	  are exposed in 3.x APIs that bypass the stateful methods or args->params lowering.
75	
76	  It supports kernel types that implement both the 2.x and 3.0 APIs,
77	  however, this is done by specializing the implementation of GemmUniversalAdapter
78	  on the two kernel API types, and thus, GemmUniversalAdapter's behaviour might
79	  differ between the two specializations.
80	*/
81	template <class GemmKernel_, class Enable = void>
82	class GemmUniversalAdapter;
83	
84	////////////////////////////////////////////////////////////////////////////////
85	////////////////////////////// CUTLASS 3.x API /////////////////////////////////
86	////////////////////////////////////////////////////////////////////////////////
87	
88	namespace detail {
89	
90	// Work-around for some DispatchPolicy types not having a Stages member.
91	// In that case, the Stages value is 0.  Most code should static_assert
92	// that the number of stages is valid.
93	
94	// Whether DispatchPolicy::Stages is valid.
95	// It should also be convertible to int, but if not, that will show up
96	// as a build error when GemmUniversalAdapter attempts to assign it to kStages.
97	template <class DispatchPolicy, class Enable = void>
98	struct has_Stages : cute::false_type {};
99	
100	template <class DispatchPolicy>
101	struct has_Stages<DispatchPolicy, cute::void_t<decltype(DispatchPolicy::Stages)>> : cute::true_type {};
102	
103	template<class DispatchPolicy>
104	constexpr int stages_member(DispatchPolicy) {
105	  if constexpr (has_Stages<DispatchPolicy>::value) {
106	    return DispatchPolicy::Stages;
107	  }
108	  else {
109	    return 0;
110	  }
111	}
112	
113	template <class GemmKernel, class = void>
114	struct IsDistGemmKernel : cute::false_type { };
115	
116	template <typename GemmKernel>
117	struct IsDistGemmKernel<GemmKernel, cute::void_t<typename GemmKernel::TP>>
118	    : cute::true_type { };
119	
120	} // namespace detail
121	
122	template <class GemmKernel_>
123	class GemmUniversalAdapter<
124	  GemmKernel_,
125	  cute::enable_if_t<gemm::detail::IsCutlass3GemmKernel<GetUnderlyingKernel_t<GemmKernel_>>::value>>
126	{
127	public:
128	  using GemmKernel = GetUnderlyingKernel_t<GemmKernel_>;
129	  using TileShape = typename GemmKernel::TileShape;
130	  using ElementA = typename GemmKernel::ElementA;
131	  using ElementB = typename GemmKernel::ElementB;
132	  using ElementC = typename GemmKernel::ElementC;
133	  using ElementD = typename GemmKernel::ElementD;
134	  using ElementAccumulator = typename GemmKernel::ElementAccumulator;
135	  using DispatchPolicy = typename GemmKernel::DispatchPolicy;
136	  using CollectiveMainloop = typename GemmKernel::CollectiveMainloop;
137	  using CollectiveEpilogue = typename GemmKernel::CollectiveEpilogue;
138	
139	  // Map back to 2.x type as best as possible
140	  using LayoutA = gemm::detail::StrideToLayoutTagA_t<typename GemmKernel::StrideA>;
141	  using LayoutB = gemm::detail::StrideToLayoutTagB_t<typename GemmKernel::StrideB>;
142	  using LayoutC = gemm::detail::StrideToLayoutTagC_t<typename GemmKernel::StrideC>;
143	  using LayoutD = gemm::detail::StrideToLayoutTagC_t<typename GemmKernel::StrideD>;
144	
145	  static bool const kEnableCudaHostAdapter = CUTLASS_ENABLE_CUDA_HOST_ADAPTER;
146	
147	  static ComplexTransform const kTransformA = cute::is_same_v<typename GemmKernel::CollectiveMainloop::TransformA, cute::conjugate> ?
148	                                              ComplexTransform::kConjugate : ComplexTransform::kNone;
149	  static ComplexTransform const kTransformB = cute::is_same_v<typename GemmKernel::CollectiveMainloop::TransformB, cute::conjugate> ?
150	                                              ComplexTransform::kConjugate : ComplexTransform::kNone;
151	
152	  // Legacy: Assume MultiplyAdd only since we do not use this tag type in 3.0
153	  using MathOperator = cutlass::arch::OpMultiplyAdd;
154	
155	  using OperatorClass = cutlass::detail::get_operator_class_t<typename CollectiveMainloop::TiledMma>;
156	
157	  using ArchTag = typename GemmKernel::ArchTag;
158	
159	  // NOTE: Assume identity swizzle for now
160	  using ThreadblockSwizzle = cutlass::gemm::threadblock::GemmIdentityThreadblockSwizzle<>;
161	
162	  // Assume TiledMma's ShapeMNK is the same as 2.x's ThreadblockShape
163	  using ThreadblockShape = cutlass::gemm::GemmShape<
164	      cute::size<0>(TileShape{}),
165	      cute::size<1>(TileShape{}),
166	      cute::size<2>(TileShape{})>;
167	
168	  using ClusterShape = cutlass::gemm::GemmShape<
169	      cute::size<0>(typename GemmKernel::DispatchPolicy::ClusterShape{}),
170	      cute::size<1>(typename GemmKernel::DispatchPolicy::ClusterShape{}),
171	      cute::size<2>(typename GemmKernel::DispatchPolicy::ClusterShape{})>;
172	
173	  // Instruction shape is easy too, since we get that directly from our TiledMma's atom shape
174	  using InstructionShape = cutlass::gemm::GemmShape<
175	      cute::size<0>(typename CollectiveMainloop::TiledMma::AtomShape_MNK{}),
176	      cute::size<1>(typename CollectiveMainloop::TiledMma::AtomShape_MNK{}),
177	      cute::size<2>(typename CollectiveMainloop::TiledMma::AtomShape_MNK{})>;
178	
179	  // Legacy: provide a correct warp count, but no reliable warp shape
180	  static int const kThreadCount = GemmKernel::MaxThreadsPerBlock;
181	
182	  // Warp shape is not a primary API type in 3.x
183	  // But we can best approximate it by inspecting the TiledMma
184	  // For this, we make the assumption that we always have 4 warps along M, and rest along N, none along K
185	  // We also always round up the warp count to 4 if the tiled mma is smaller than 128 threads
186	  static constexpr int WarpsInMma = cute::max(4, CUTE_STATIC_V(cute::size(typename GemmKernel::TiledMma{})) / 32);
187	  static constexpr int WarpsInMmaM = 4;
188	  static constexpr int WarpsInMmaN = cute::ceil_div(WarpsInMma, WarpsInMmaM);
189	  using WarpCount = cutlass::gemm::GemmShape<WarpsInMmaM, WarpsInMmaN, 1>;
190	  using WarpShape = cutlass::gemm::GemmShape<
191	      CUTE_STATIC_V(cute::tile_size<0>(typename CollectiveMainloop::TiledMma{})) / WarpsInMmaM,
192	      CUTE_STATIC_V(cute::tile_size<1>(typename CollectiveMainloop::TiledMma{})) / WarpsInMmaN,
193	      CUTE_STATIC_V(cute::tile_size<2>(typename CollectiveMainloop::TiledMma{}))>;
194	
195	  static int constexpr kStages = detail::stages_member(typename CollectiveMainloop::DispatchPolicy{});
196	
197	  // Inspect TiledCopy for A and B to compute the alignment size
198	  static int constexpr kAlignmentA = cutlass::detail::get_alignment_count_from_gmem_tiled_copy<
199	      typename CollectiveMainloop::GmemTiledCopyA, ElementA, typename CollectiveMainloop::TiledMma::ValTypeA>();
200	  static int constexpr kAlignmentB = cutlass::detail::get_alignment_count_from_gmem_tiled_copy<
201	      typename CollectiveMainloop::GmemTiledCopyB, ElementB, typename CollectiveMainloop::TiledMma::ValTypeB>();
202	  static int constexpr kAlignmentC = cutlass::detail::get_alignment_count_from_gmem_tiled_copy<
203	      typename CollectiveEpilogue::GmemTiledCopyC, ElementC>();
204	  static int constexpr kAlignmentD = cutlass::detail::get_alignment_count_from_gmem_tiled_copy<
205	      typename CollectiveEpilogue::GmemTiledCopyD, ElementD>();
206	
207	  using EpilogueOutputOp = typename CollectiveEpilogue::ThreadEpilogueOp;
208	
209	  // Split-K preserves splits that are 128b aligned
210	  static int constexpr kSplitKAlignment = cute::max(
211	      128 / sizeof_bits<ElementA>::value, 128 / sizeof_bits<ElementB>::value);
212	
213	  /// Argument structure: User API
214	  using Arguments = typename GemmKernel::Arguments;
215	  /// Argument structure: Kernel API
216	  using Params = typename GemmKernel::Params;
217	
218	private:
219	
220	  /// Kernel API parameters object
221	  Params params_;
222	
223	public:
224	
225	  /// Access the Params structure
226	  Params const& params() const {
227	    return params_;
228	  }
229	
230	  /// Determines whether the GEMM can execute the given problem.
231	  static Status
232	  can_implement(Arguments const& args) {
233	    if (GemmKernel::can_implement(args)) {
234	      return Status::kSuccess;
235	    }
236	    else {
237	      return Status::kInvalid;
238	    }
239	  }
240	
241	  /// Gets the workspace size
242	  static size_t
243	  get_workspace_size(Arguments const& args) {
244	    size_t workspace_bytes = 0;
245	    if (args.mode == GemmUniversalMode::kGemmSplitKParallel) {
246	      workspace_bytes += sizeof(int) * size_t(cute::size<0>(TileShape{})) * size_t(cute::size<1>(TileShape{}));
247	    }
248	
249	    workspace_bytes += GemmKernel::get_workspace_size(args);
250	
251	    CUTLASS_TRACE_HOST("  workspace_bytes: " << workspace_bytes);
252	
253	    return workspace_bytes;
254	  }
255	
256	  /// Computes the grid shape
257	  static dim3
258	  get_grid_shape(Arguments const& args, void* workspace = nullptr) {
259	    auto tmp_params = GemmKernel::to_underlying_arguments(args, workspace);
260	    return GemmKernel::get_grid_shape(tmp_params);
261	  }
262	
263	  /// Computes the grid shape
264	  static dim3
265	  get_grid_shape(Params const& params) {
266	    return GemmKernel::get_grid_shape(params);
267	  }
268	
269	  /// Computes the maximum number of active blocks per multiprocessor
270	  static int maximum_active_blocks(int /* smem_capacity */ = -1) {
271	    CUTLASS_TRACE_HOST("GemmUniversal::maximum_active_blocks()");
272	    int max_active_blocks = -1;
273	    int smem_size = GemmKernel::SharedStorageSize;
274	
275	    // first, account for dynamic smem capacity if needed
276	    cudaError_t result;
277	    if (smem_size >= (48 << 10)) {
278	      CUTLASS_TRACE_HOST("  Setting smem size to " << smem_size);
279	      result = cudaFuncSetAttribute(
280	          device_kernel<GemmKernel>,
281	          cudaFuncAttributeMaxDynamicSharedMemorySize,
282	          smem_size);
283	      if (cudaSuccess != result) {
284	        result = cudaGetLastError(); // to clear the error bit
285	        CUTLASS_TRACE_HOST(
286	          "  cudaFuncSetAttribute() returned error: "
287	          << cudaGetErrorString(result));
288	        return -1;
289	      }
290	    }
291	
292	    // query occupancy after setting smem size
293	    result = cudaOccupancyMaxActiveBlocksPerMultiprocessor(
294	        &max_active_blocks,
295	        device_kernel<GemmKernel>,
296	        GemmKernel::MaxThreadsPerBlock,
297	        smem_size);
298	
299	    if (cudaSuccess != result) {
300	      result = cudaGetLastError(); // to clear the error bit
301	      CUTLASS_TRACE_HOST(
302	        "  cudaOccupancyMaxActiveBlocksPerMultiprocessor() returned error: "
303	        << cudaGetErrorString(result));
304	      return -1;
305	    }
306	
307	    CUTLASS_TRACE_HOST("  max_active_blocks: " << max_active_blocks);
308	    return max_active_blocks;
309	  }
310	
311	  /// Initializes GEMM state from arguments.
312	  Status
313	  initialize(
314	    Arguments const& args,
315	    void* workspace = nullptr,
316	    cudaStream_t stream = nullptr,
317	    CudaHostAdapter* cuda_adapter = nullptr) {
318	
319	    CUTLASS_TRACE_HOST("GemmUniversal::initialize() - workspace "
320	      << workspace << ", stream: " << (stream ? "non-null" : "null"));
321	
322	    // Initialize the workspace
323	    Status status = GemmKernel::initialize_workspace(args, workspace, stream, cuda_adapter);
324	    if (status != Status::kSuccess) {
325	      return status;
326	    }
327	    // Initialize the Params structure
328	    params_ = GemmKernel::to_underlying_arguments(args, workspace);
329	    // Don't set the function attributes - require the CudaHostAdapter to set it.
330	    if constexpr (kEnableCudaHostAdapter) {
331	      CUTLASS_ASSERT(cuda_adapter);
332	      return Status::kSuccess;
333	    }
334	    else {
335	      //
336	      // Account for dynamic smem capacity if needed
337	      //
338	      int smem_size = GemmKernel::SharedStorageSize;
339	
340	      CUTLASS_ASSERT(cuda_adapter == nullptr);
341	
342	      if (smem_size >= (48 << 10)) {
343	        CUTLASS_TRACE_HOST("  Setting smem size to " << smem_size);
344	        cudaError_t result = cudaFuncSetAttribute(
345	            device_kernel<GemmKernel>,
346	            cudaFuncAttributeMaxDynamicSharedMemorySize,
347	            smem_size);
348	        if (cudaSuccess != result) {
349	          result = cudaGetLastError(); // to clear the error bit
350	          CUTLASS_TRACE_HOST("  cudaFuncSetAttribute() returned error: " << cudaGetErrorString(result));
351	          return Status::kErrorInternal;
352	        }
353	      }
354	    }
355	    return Status::kSuccess;
356	  }
357	
358	  /// Update API is preserved in 3.0, but does not guarantee a lightweight update of params.
359	  Status
360	  update(Arguments const& args, void* workspace = nullptr) {
361	    CUTLASS_TRACE_HOST("GemmUniversal()::update() - workspace: " << workspace);
362	
363	    size_t workspace_bytes = get_workspace_size(args);
364	    if (workspace_bytes > 0 && nullptr == workspace) {
365	      return Status::kErrorWorkspaceNull;
366	    }
367	
368	    params_ = GemmKernel::to_underlying_arguments(args, workspace);
369	    return Status::kSuccess;
370	  }
371	
372	  /// Primary run() entry point API that is static allowing users to create and manage their own params.
373	  /// Supplied params struct must be construct by calling GemmKernel::to_underlying_arguments()
374	  static Status
375	  run(Params& params,
376	      cudaStream_t stream = nullptr,
377	      CudaHostAdapter *cuda_adapter = nullptr,
378	      bool launch_with_pdl = false) {
379	    CUTLASS_TRACE_HOST("GemmUniversal::run()");
380	    dim3 const block = GemmKernel::get_block_shape();
381	    dim3 const grid = get_grid_shape(params);
382	
383	    // configure smem size and carveout
384	    int smem_size = GemmKernel::SharedStorageSize;
385	
386	    Status launch_result{ Status::kSuccess };
387	    // Use extended launch API only for mainloops that use it
388	    if constexpr (GemmKernel::ArchTag::kMinComputeCapability >= 90) {
389	#if (CUTLASS_DEBUG_TRACE_LEVEL > 1)
390	      CUTLASS_TRACE_HOST("GemmUniversal::run: Use extended launch API");
391	#endif
392	      [[maybe_unused]] constexpr bool is_static_1x1x1 =
393	        cute::is_static_v<typename GemmKernel::DispatchPolicy::ClusterShape> and
394	        cute::size(typename GemmKernel::DispatchPolicy::ClusterShape{}) == 1;
395	      [[maybe_unused]] dim3 cluster(cute::size<0>(typename GemmKernel::DispatchPolicy::ClusterShape{}),
396	        cute::size<1>(typename GemmKernel::DispatchPolicy::ClusterShape{}),
397	        cute::size<2>(typename GemmKernel::DispatchPolicy::ClusterShape{}));
398	      
399	      // Dynamic cluster support
400	      [[maybe_unused]] dim3 fallback_cluster = dim3{0,0,0};
401	      if constexpr (GemmKernel::ArchTag::kMinComputeCapability == 100 
402	                    || GemmKernel::ArchTag::kMinComputeCapability == 101
403	                    || GemmKernel::ArchTag::kMinComputeCapability == 103
404	                    ) {
405	        if constexpr (!cute::is_static_v<typename GemmKernel::DispatchPolicy::ClusterShape>) {
406	          if constexpr (detail::IsDistGemmKernel<GemmKernel>::value) {
407	            fallback_cluster = params.base.hw_info.cluster_shape_fallback;
408	            cluster = params.base.hw_info.cluster_shape;
409	          } else {
410	            fallback_cluster = params.hw_info.cluster_shape_fallback;
411	            cluster = params.hw_info.cluster_shape;
412	          }
413	        }
414	      }
415	      
416	      [[maybe_unused]] void* kernel_params[] = {&params};
417	
418	      if constexpr (kEnableCudaHostAdapter) {
419	        //
420	        // Use the cuda host adapter
421	        //
422	        CUTLASS_ASSERT(cuda_adapter);
423	        if (cuda_adapter) {
424	          if (launch_with_pdl) {
425	            CUTLASS_TRACE_HOST(
426	              "GemmUniversal::run() does not support launching with PDL and a custom cuda adapter.");
427	            return Status::kErrorInternal;
428	          }
429	#if (CUTLASS_DEBUG_TRACE_LEVEL > 1)
430	          CUTLASS_TRACE_HOST("GemmUniversal::run: Launching kernel with CUDA host adapter");
431	#endif
432	          if constexpr (is_static_1x1x1) {
433	            launch_result = cuda_adapter->launch(grid,
434	                                                block,
435	                                                smem_size,
436	                                                stream,
437	                                                kernel_params,
438	                                                0);
439	          }
440	          else {
441	            launch_result = cuda_adapter->launch(grid,
442	                                                cluster,
443	                                                fallback_cluster, 
444	                                                block,
445	                                                smem_size,
446	                                                stream,
447	                                                kernel_params,
448	                                                0);
449	          }
450	        }
451	        else {
452	          CUTLASS_TRACE_HOST("GemmUniversal::run: kEnableCudaHostAdapter is true, but CUDA host adapter is null");
453	          return Status::kErrorInternal;
454	        }
455	      }
456	      else {
457	        CUTLASS_ASSERT(cuda_adapter == nullptr);
458	        [[maybe_unused]] void const* kernel = (void const*) device_kernel<GemmKernel>;
459	        static constexpr bool kClusterLaunch = GemmKernel::ArchTag::kMinComputeCapability == 90;
460	        if constexpr (kClusterLaunch) {
461	          if constexpr (is_static_1x1x1) {
462	#if (CUTLASS_DEBUG_TRACE_LEVEL > 1)
463	            CUTLASS_TRACE_HOST("GemmUniversal::run: Launching static 1x1x1 kernel");
464	#endif
465	            launch_result = cutlass::kernel_launch<GemmKernel>(
466	              grid, block, smem_size, stream, params, launch_with_pdl);
467	            if (launch_result != Status::kSuccess) {
468	              CUTLASS_TRACE_HOST("GemmUniversal::run: cutlass::kernel_launch reports failure");
469	            }
470	#if (CUTLASS_DEBUG_TRACE_LEVEL > 1)
471	            else {
472	              CUTLASS_TRACE_HOST("GemmUniversal::run: cutlass::kernel_launch reports success");
473	            }
474	#endif
475	          }
476	          else {
477	#if (CUTLASS_DEBUG_TRACE_LEVEL > 1)
478	            CUTLASS_TRACE_HOST("GemmUniversal::run: Launching dynamic cluster kernel");
479	#endif
480	            launch_result = ClusterLauncher::launch(
481	              grid, cluster, block, smem_size, stream, kernel, kernel_params, launch_with_pdl);
482	          }
483	        }
484	        
485	        else {
486	          if constexpr (GemmKernel::ArchTag::kMinComputeCapability == 100
487	                        || GemmKernel::ArchTag::kMinComputeCapability == 101
488	                        || GemmKernel::ArchTag::kMinComputeCapability == 120
489	                        || GemmKernel::ArchTag::kMinComputeCapability == 103
490	                       ) {
491	            if constexpr (is_static_1x1x1) {
492	#if (CUTLASS_DEBUG_TRACE_LEVEL > 1)
493	              CUTLASS_TRACE_HOST("GemmUniversal::run: Launching static 1x1x1 kernel");
494	#endif
495	              launch_result = cutlass::kernel_launch<GemmKernel>(grid, block, smem_size, stream, params, launch_with_pdl);
496	              if (launch_result != Status::kSuccess) {
497	                CUTLASS_TRACE_HOST("GemmUniversal::run: cutlass::kernel_launch reports failure");
498	              }
499	#if (CUTLASS_DEBUG_TRACE_LEVEL > 1)
500	              else {
501	                CUTLASS_TRACE_HOST("GemmUniversal::run: cutlass::kernel_launch reports success");
502	              }
503	#endif
504	            }
505	            else {
506	#if (CUTLASS_DEBUG_TRACE_LEVEL > 1)
507	              CUTLASS_TRACE_HOST("GemmUniversal::run: Launching kernel with fall-back cluster");
508	#endif
509	              launch_result = ClusterLauncher::launch_with_fallback_cluster(
510	                grid, 
511	                cluster,
512	                fallback_cluster,
513	                block,
514	                smem_size,
515	                stream,
516	                kernel,
517	                kernel_params,
518	                launch_with_pdl);
519	            }
520	          }
521	        }
522	        
523	      }
524	    }
525	    else {
526	      launch_result = Status::kSuccess;
527	      cutlass::arch::synclog_setup();
528	
529	      if constexpr (kEnableCudaHostAdapter) {
530	        CUTLASS_ASSERT(cuda_adapter);
531	        if (cuda_adapter) {
532	          void* kernel_params[] = {&params};
533	#if (CUTLASS_DEBUG_TRACE_LEVEL > 1)
534	          CUTLASS_TRACE_HOST("GemmUniversal::run: Launching kernel with CUDA host adapter");
535	#endif
536	          launch_result = cuda_adapter->launch(
537	            grid, block, smem_size, stream, kernel_params, 0
538	          );
539	
540	        }
541	        else {
542	          CUTLASS_TRACE_HOST("GemmUniversal::run: CUDA host adapter is null");
543	          return Status::kErrorInternal;
544	        }
545	      }
546	      else {
547	        CUTLASS_ASSERT(cuda_adapter == nullptr);
548	#if (CUTLASS_DEBUG_TRACE_LEVEL > 1)
549	        CUTLASS_TRACE_HOST("GemmUniversal::run: Launching kernel with cutlass::kernel_launch");
550	#endif
551	        launch_result = cutlass::kernel_launch<GemmKernel>(
552	          grid, block, smem_size, stream, params, launch_with_pdl);
553	        if (launch_result != Status::kSuccess) {
554	          CUTLASS_TRACE_HOST("GemmUniversal::run: cutlass::kernel_launch reports failure");
555	        }
556	#if (CUTLASS_DEBUG_TRACE_LEVEL > 1)
557	        else {
558	          CUTLASS_TRACE_HOST("GemmUniversal::run: cutlass::kernel_launch reports success");
559	        }
560	#endif
561	      }
562	    }
563	
564	    cudaError_t result = cudaGetLastError();
565	    if (cudaSuccess == result && Status::kSuccess == launch_result) {
566	#if (CUTLASS_DEBUG_TRACE_LEVEL > 1)
567	      CUTLASS_TRACE_HOST("GemmUniversal::run: cudaGetLastError reports success");
568	#endif
569	      return Status::kSuccess;
570	    }
571	    else {
572	      CUTLASS_TRACE_HOST("  Kernel launch failed. Reason: " << result);
573	      return Status::kErrorInternal;
574	    }
575	  }
576	
577	  //
578	  // Non-static launch overloads that first create and set the internal params struct of this kernel handle.
579	  //
580	
581	  /// Launches the kernel after first constructing Params internal state from supplied arguments.
582	  Status
583	  run(
584	    Arguments const& args,
585	    void* workspace = nullptr,
586	    cudaStream_t stream = nullptr,
587	    CudaHostAdapter *cuda_adapter = nullptr,
588	    bool launch_with_pdl = false
589	  ) {
590	    Status status = initialize(args, workspace, stream, cuda_adapter);
591	
592	    if (Status::kSuccess == status) {
593	      status = run(params_, stream, cuda_adapter, launch_with_pdl);
594	    }
595	    return status;
596	  }
597	
598	  /// Launches the kernel after first constructing Params internal state from supplied arguments.
599	  Status
600	  operator()(
601	    Arguments const& args,
602	    void* workspace = nullptr,
603	    cudaStream_t stream = nullptr,
604	    CudaHostAdapter *cuda_adapter = nullptr,
605	    bool launch_with_pdl = false) {
606	    return run(args, workspace, stream, cuda_adapter, launch_with_pdl);
607	  }
608	
609	  /// Overload that allows a user to re-launch the same kernel without updating internal params struct.
610	  Status
611	  run(
612	    cudaStream_t stream = nullptr,
613	    CudaHostAdapter *cuda_adapter = nullptr,
614	    bool launch_with_pdl = false) {
615	    return run(params_, stream, cuda_adapter, launch_with_pdl);
616	  }
617	
618	  /// Overload that allows a user to re-launch the same kernel without updating internal params struct.
619	  Status
620	  operator()(cudaStream_t stream = nullptr, CudaHostAdapter *cuda_adapter = nullptr, bool launch_with_pdl = false) {
621	    return run(params_, stream, cuda_adapter, launch_with_pdl);
622	  }
623	};
