628	
629	template <class GemmKernel_>
630	class GemmUniversalAdapter<
631	  GemmKernel_,
632	  cute::enable_if_t<not gemm::detail::IsCutlass3GemmKernel<GetUnderlyingKernel_t<GemmKernel_>>::value>>
633	{
634	public:
635	
636	  using GemmKernel = GetUnderlyingKernel_t<GemmKernel_>;
637	
638	  static bool const kInternalTranspose =
639	    !cutlass::epilogue::threadblock::detail::is_2x_evt_v<typename GemmKernel::Epilogue> &&  // 2.x EVT does not require internal transpose
640	    cute::is_same<typename GemmKernel::LayoutC, cutlass::layout::RowMajor>::value;
641	
642	  using ThreadblockShape = typename GemmKernel::Mma::Shape;
643	  using WarpShape = typename GemmKernel::WarpShape;
644	  using InstructionShape = typename GemmKernel::InstructionShape;
645	
646	  // warp-level, arch-level (instruction), math operator
647	  using WarpMmaOperator = typename GemmKernel::Mma::Policy::Operator;
648	  using ArchMmaOperator = typename WarpMmaOperator::ArchMmaOperator;
649	  using MathOperator = typename WarpMmaOperator::MathOperator;
650	
651	  // Operator class and arch tag extract bottom-up
652	  // set it for top-level gemm device-level template
653	  using OperatorClass = typename WarpMmaOperator::OperatorClass;
654	  using ArchTag = typename WarpMmaOperator::ArchTag;
655	
656	  // Type, layout, and complex transform deliberately exchanged with B
657	  using MapArguments = kernel::detail::MapArguments<
658	    typename GemmKernel::ElementA,
659	    typename GemmKernel::LayoutA,
660	    GemmKernel::kTransformA,
661	    GemmKernel::kAlignmentA,
662	    typename GemmKernel::ElementB,
663	    typename GemmKernel::LayoutB,
664	    GemmKernel::kTransformB,
665	    GemmKernel::kAlignmentB,
666	    typename GemmKernel::LayoutC,
667	    kInternalTranspose
668	  >;
669	
670	  using ElementA = typename MapArguments::ElementA;
671	  using LayoutA = typename MapArguments::LayoutA;
672	  static ComplexTransform const kTransformA = MapArguments::kTransformA;
673	  static int const kAlignmentA = MapArguments::kAlignmentA;
674	
675	  using ElementB = typename MapArguments::ElementB;
676	  using LayoutB = typename MapArguments::LayoutB;
677	  static ComplexTransform const kTransformB = MapArguments::kTransformB;
678	  static int const kAlignmentB = MapArguments::kAlignmentB;
679	
680	  using ElementC = typename GemmKernel::ElementC;
681	  using LayoutC = typename MapArguments::LayoutC;
682	  static int const kAlignmentC = GemmKernel::kAlignmentC;
683	
684	  // C and D same type for 2.x kernel
685	  using ElementD = ElementC;
686	  using LayoutD = LayoutC;
687	
688	  using TensorRefA = TensorRef<ElementA const, LayoutA>;
689	  using TensorRefB = TensorRef<ElementB const, LayoutB>;
690	  using TensorRefC = TensorRef<ElementC const, LayoutC>;
691	  using TensorRefD = TensorRef<ElementD, LayoutD>;
692	
693	  static int const kStages = GemmKernel::Mma::kStages;
694	
695	  using EpilogueOutputOp = typename GemmKernel::EpilogueOutputOp;
696	  using ElementAccumulator = typename EpilogueOutputOp::ElementAccumulator;
697	  using ThreadblockSwizzle = typename GemmKernel::ThreadblockSwizzle;
698	  using UnderlyingOperator = GemmUniversalBase<GemmKernel>;
699	  using Arguments = typename UnderlyingOperator::Arguments;
700	
701	private:
702	
703	  UnderlyingOperator underlying_operator_;
704	
705	public:
706	
707	  /// Constructs the GEMM.
708	  GemmUniversalAdapter() { }
709	
710	  /// Helper to construct a transposed equivalent for the underlying GEMM operator
711	  static Arguments to_underlying_arguments(Arguments const &args) {
712	    if (kInternalTranspose) {
713	      return args.transposed_problem();
714	    }
715	    else {
716	      return args;
717	    }
718	  }
719	
720	  /// Determines whether the GEMM can execute the given problem.
721	  static Status can_implement(Arguments const &args, CudaHostAdapter *cuda_adapter = nullptr) {
722	
723	    return UnderlyingOperator::can_implement(to_underlying_arguments(args), cuda_adapter);
724	  }
725	
726	  /// Gets the workspace size
727	  static size_t get_workspace_size(Arguments const &args, CudaHostAdapter *cuda_adapter = nullptr) {
728	
729	    return UnderlyingOperator::get_workspace_size(to_underlying_arguments(args), cuda_adapter);
730	  }
731	
732	  /// Computes the grid shape
733	  static dim3 get_grid_shape(Arguments const &args) {
734	    return UnderlyingOperator::get_grid_shape(to_underlying_arguments(args));
735	  }
736	
737	  /// Computes the maximum number of active blocks per multiprocessor
738	  static int maximum_active_blocks(int smem_capacity = -1) {
739	    return UnderlyingOperator::maximum_active_blocks(smem_capacity);
740	  }
741	
742	  /// Initializes GEMM state from arguments.
743	  Status initialize(
744	    Arguments const &args,
745	    void *workspace = nullptr,
746	    cudaStream_t stream = nullptr,
747	    CudaHostAdapter *cuda_adapter = nullptr
748	  ) {
749	
750	    return underlying_operator_.initialize(to_underlying_arguments(args), workspace, stream, cuda_adapter);
751	  }
752	
753	  /// Lightweight update given a subset of arguments.
754	  Status update(Arguments const &args) {
755	
756	    return underlying_operator_.update(to_underlying_arguments(args));
757	  }
758	
759	  /// Runs the kernel using initialized state.
760	  Status run(
761	    cudaStream_t stream = nullptr,
762	    CudaHostAdapter *cuda_adapter = nullptr) {
763	
764	    return underlying_operator_.run(stream, cuda_adapter);
765	  }
766	
767	  /// Runs the kernel using initialized state.
768	  Status operator()(
769	    cudaStream_t stream = nullptr,
770	    CudaHostAdapter *cuda_adapter = nullptr) {
771	
772	    return run(stream);
773	  }
774	
775	  /// Runs the kernel using initialized state.
776	  Status operator()(
777	    Arguments const &args,
778	    void *workspace = nullptr,
779	    cudaStream_t stream = nullptr,
780	    CudaHostAdapter *cuda_adapter = nullptr) {
781	
782	    Status status = initialize(args, workspace, stream, cuda_adapter);
783	
784	    if (status == Status::kSuccess) {
785	      status = run(stream, cuda_adapter);
786	    }
787	
788	    return status;
789	  }
790	};
