template<class LayoutC>
constexpr bool
is_m_major_C() {
  return is_major<0,TagToStrideC_t<LayoutC>>();
}

template<class LayoutC>
constexpr bool
is_n_major_C() {
  return is_major<1,TagToStrideC_t<LayoutC>>();
}

